import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { Form, Button, Alert, Card } from 'react-bootstrap';

const CreateProblem = () => {
  const [formData, setFormData] = useState({
    title: '',
    category: 'algebra',
    difficulty: 'easy',
    description: ''
  });
  const [message, setMessage] = useState({ text: '', variant: '' });
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    console.log("Submitting with data:", formData); // Add this
    
    try {
      const token = localStorage.getItem('token');
      console.log("Token being used:", token); // Verify token
      
      const response = await axios.post('http://localhost:5000/api/problems', formData, {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        timeout: 5000 // 5 second timeout
      });
  
      
      console.log("Response received:", response); // Add this
      // ... rest of your code

      setMessage({ 
        text: 'Problem created successfully!', 
        variant: 'success' 
      });
      setFormData({
        title: '',
        category: 'algebra',
        difficulty: 'easy',
        description: ''
      });
      
      // Redirect to problem page after 2 seconds
      setTimeout(() => {
        navigate(`/problems/${response.data._id}`);
      }, 2000);
    } catch (error) {
      console.error("Full error:", error);
      setMessage({
        text: error.response?.data?.message || 
             error.message || 
             "Network error - check console",
        variant: 'danger'
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Card className="p-4" style={{ maxWidth: '800px', margin: '2rem auto' }}>
      <h2 className="text-center mb-4">Create New Math Problem</h2>
      {message.text && (
        <Alert variant={message.variant} dismissible onClose={() => setMessage({ text: '', variant: '' })}>
          {message.text}
        </Alert>
      )}
      <Form onSubmit={handleSubmit}>
        <Form.Group className="mb-3">
          <Form.Label>Title</Form.Label>
          <Form.Control
            type="text"
            name="title"
            value={formData.title}
            onChange={handleChange}
            required
          />
        </Form.Group>

        <Form.Group className="mb-3">
          <Form.Label>Category</Form.Label>
          <Form.Select
            name="category"
            value={formData.category}
            onChange={handleChange}
            required
          >
            <option value="algebra">Algebra</option>
            <option value="geometry">Geometry</option>
            <option value="calculus">Calculus</option>
            <option value="trigonometry">Trigonometry</option>
          </Form.Select>
        </Form.Group>

        <Form.Group className="mb-3">
          <Form.Label>Difficulty</Form.Label>
          <Form.Select
            name="difficulty"
            value={formData.difficulty}
            onChange={handleChange}
            required
          >
            <option value="easy">Easy</option>
            <option value="medium">Medium</option>
            <option value="hard">Hard</option>
          </Form.Select>
        </Form.Group>

        <Form.Group className="mb-3">
          <Form.Label>Description</Form.Label>
          <Form.Control
            as="textarea"
            name="description"
            rows={6}
            value={formData.description}
            onChange={handleChange}
            required
          />
        </Form.Group>

        <Button 
          variant="primary" 
          type="submit" 
          disabled={loading}
        >
          {loading ? 'Creating...' : 'Create Problem'}
        </Button>
      </Form>
    </Card>
  );
};

export default CreateProblem;
